const soul = $('Load Soul').all().map(i => i.json);
const agents = $('Load Agents Config').all().map(i => i.json);
const user = $('Load User Profile').first()?.json || {};
const history = $('Load Conversation History').all().map(i => i.json);
const userMessage = $('Telegram Trigger').first().json.message?.text || '';
const chatId = $('Telegram Trigger').first().json.message?.chat?.id;
const userId = $('Telegram Trigger').first().json.message?.from?.id;
const soulText = soul.map(s => `## ${s.key}
${s.content}`).join('

');
const agentText = agents.map(a => `## ${a.key}
${a.content}`).join('

');
const userText = user.display_name
  ? `Name: ${user.display_name} (${user.name || 'unknown'})
Timezone: ${user.timezone || 'UTC'}
Context: ${user.context || ''}
Preferences: ${JSON.stringify(user.preferences || {})}`
  : 'No stored user profile.';
const historyText = history.reverse().map(h => `${h.role}: ${h.content}`).join('
');
const toolHint = "

# IMPORTANT TOOLS
- Wekan MCP: use this workflow whenever the request affects the wedding board, vendor follow-ups, deadlines, or task status. Send a structured JSON payload with the intended board/list/card/checklist change. For any mutation, call it first without confirmed=true so it can draft the exact action. After the user replies with confirm/yes/approved, call it again with the same payload and confirmed=true to execute.
- Reminder: creates scheduled Telegram reminders.
- Memory Search and Memory Save: use them to recall and store important long-term planning details.
- MCP Builder and WorkflowBuilder are secondary tools; do not use them instead of the Wekan workflow for board management.";
const systemPrompt = "# WEDDING SOUL
" + soulText + '

# AGENT CONFIG
' + agentText + '

# USER PROFILE
' + userText + '

# RECENT CONVERSATION
' + historyText + toolHint + '

# OPERATING RULES
You are operating in a shared wedding-planning chat. Before any Wekan mutation, call Wekan MCP once to draft the exact change and use that preview to ask for confirmation. After explicit approval, call Wekan MCP again with the same payload and confirmed=true. Read-only lookups can proceed without confirmation.';
return [{
  json: {
    systemPrompt,
    userMessage,
    chatId: chatId ? String(chatId) : null,
    userId: userId ? String(userId) : null,
    sessionId: chatId ? `telegram:${chatId}` : null
  }
}];

// Save conversation to Postgres
const userMessage = $('Build System Prompt').first().json.userMessage;
const assistantMessage = $('AI Agent').first().json.output;
const sessionId = $('Build System Prompt').first().json.sessionId;
const userId = $('Build System Prompt').first().json.userId;

return [{
  json: {
    userMessage,
    assistantMessage,
    sessionId,
    userId
  }
}];

let input;
try { input = JSON.parse(query); } catch(e) { input = {action:'list'}; }
const apiKey = '' + (process.env.N8N_API_KEY || '') + '';
const hdrs = {'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json'};
let result;
if (input.action === 'list') {
  result = await helpers.httpRequest({method:'GET', url:'' + (process.env.N8N_INTERNAL_URL || 'http://127.0.0.1:5678') + '/api/v1/workflows', headers: hdrs});
} else if (input.action === 'get' && input.workflowId) {
  result = await helpers.httpRequest({method:'GET', url:'' + (process.env.N8N_INTERNAL_URL || 'http://127.0.0.1:5678') + '/api/v1/workflows/'+input.workflowId, headers: hdrs});
} else {
  return JSON.stringify({error: 'Use action: list or get'});
}
return JSON.stringify(result);

// Debug: figure out what query actually is
const qType = typeof query;
let mcpUrl = '', toolName = '', args = {};

if (qType === 'object' && query !== null) {
  // query is already an object
  mcpUrl = query.mcp_url || '';
  toolName = query.tool_name || '';
  args = query.arguments || {};
} else if (qType === 'string') {
  try {
    const parsed = JSON.parse(query);
    mcpUrl = parsed.mcp_url || '';
    toolName = parsed.tool_name || '';
    args = parsed.arguments || {};
  } catch(e) {
    return 'Parse error: query=' + String(query).substring(0,200) + ' type=' + qType;
  }
} else {
  return 'Unexpected query type: ' + qType + ' value: ' + String(query).substring(0,200);
}

if (typeof args === 'string') try { args = JSON.parse(args); } catch(e) {}
if (!mcpUrl || !toolName) return 'Error: mcp_url=' + mcpUrl + ' tool_name=' + toolName + ' (query type was: ' + qType + ')';

try {
  // 1. Initialize
  const init = await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: {'Content-Type':'application/json','Accept':'application/json, text/event-stream'},
    body: JSON.stringify({jsonrpc:'2.0',id:1,method:'initialize',params:{protocolVersion:'2024-11-05',capabilities:{},clientInfo:{name:'openclaw-mcp',version:'1.0'}}}),
    returnFullResponse: true, encoding: 'utf-8', json: false
  });
  const sid = init.headers && init.headers['mcp-session-id'];
  if (!sid) return 'MCP: No session id. Body: ' + String(init.body||init).substring(0,200);

  // 2. Initialized
  await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: {'Content-Type':'application/json','Accept':'application/json, text/event-stream','mcp-session-id':sid},
    body: JSON.stringify({jsonrpc:'2.0',method:'notifications/initialized'}),
    json: false
  });

  // 3. Call tool
  const resp = await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: {'Content-Type':'application/json','Accept':'application/json, text/event-stream','mcp-session-id':sid},
    body: JSON.stringify({jsonrpc:'2.0',id:2,method:'tools/call',params:{name:toolName,arguments:args}}),
    json: false
  });

  const bodyStr = String(resp);
  const dataLine = bodyStr.split('\n').find(l => l.startsWith('data: '));
  if (!dataLine) return 'MCP: No data. Response: ' + bodyStr.substring(0,200);
  const result = JSON.parse(dataLine.substring(6));
  if (result.error) return 'MCP Error: ' + JSON.stringify(result.error);
  return result.result?.content?.[0]?.text || JSON.stringify(result.result);
} catch(e) {
  return 'MCP Error: ' + e.message;
}
